const HOUR_MAP = {'7:00 AM':0,'8:00 AM':1,'9:00 AM':2,'10:00 AM':3,'11:00 AM':4,'12:00 PM':5,'1:00 PM':6,'2:00 PM':7,'3:00 PM':8,'4:00 PM':9,'5:00 PM':10,'6:00 PM':11,'7:00 PM':12,'8:00 PM':13,'9:00 PM':14};
const HOUR_LABELS = ['7am','8am','9am','10am','11am','12pm','1pm','2pm','3pm','4pm','5pm','6pm','7pm','8pm','9pm'];
const DAYS_LONG = ['Monday','Tuesday','Wednesday','Thursday','Friday','Saturday','Sunday'];
const THRESHOLD = 400;

